-- ============================================================
-- ALIASES (400 — sur 400 personnes aléatoires)
-- ============================================================
SELECT p.id,
       upper(substr(md5(p.numero_taj || 'alias'), 1, 8)) || '-' || upper(substr(md5(p.numero_taj), 1, 6)),
       NULL,
       (ARRAY['pseudonyme','faux_papiers','nom_usage','surnom','autre']::type_alias[])[floor(random()*5+1)::int],
       NOW() - (random() * interval '5 years')
FROM personnes p
ORDER BY random()
LIMIT 400;

-- ============================================================
-- ADRESSES (1 500 — ~1.25 par personne)
-- ============================================================
SELECT sub.* FROM (
  SELECT
    p.id,
    (floor(random()*200+1)::text || ' ' ||
     (ARRAY['Rue de la Paix','Avenue du Général de Gaulle','Boulevard Victor Hugo',
            'Rue Jean Moulin','Avenue Foch','Rue de la République',
            'Boulevard de la Liberté','Rue du 8 Mai 1945','Impasse des Lilas',
            'Allée des Roses','Chemin du Moulin','Rue Gambetta'])[floor(random()*12+1)::int]),
    lpad((floor(random()*95+1)::int * 1000 + floor(random()*999)::int)::text, 5, '0'),
    (ARRAY['Paris','Marseille','Lyon','Toulouse','Nice','Nantes','Strasbourg',
           'Montpellier','Bordeaux','Lille','Rennes','Saint-Étienne','Grenoble',
           'Dijon','Angers','Nîmes','Toulon','Reims','Le Havre','Clermont-Ferrand'])[floor(random()*20+1)::int],
    'France',
    (ARRAY['domicile','travail','derniere_connue','secondaire','parentale']::type_adresse[])[floor(random()*5+1)::int],
    CURRENT_DATE - (random() * 3650)::int,
    NOW() - (random() * interval '6 years')
  FROM personnes p
  UNION ALL
  SELECT
    p.id,
    (floor(random()*200+1)::text || ' ' ||
     (ARRAY['Rue Nationale','Rue de Rivoli','Boulevard Haussmann',
            'Rue du Faubourg Saint-Antoine','Avenue de la Gare'])[floor(random()*5+1)::int]),
    lpad((floor(random()*95+1)::int * 1000 + floor(random()*999)::int)::text, 5, '0'),
    (ARRAY['Paris','Marseille','Lyon','Bordeaux','Nantes'])[floor(random()*5+1)::int],
    'France',
    'secondaire'::type_adresse,
    CURRENT_DATE - (random() * 1825)::int,
    NOW() - (random() * interval '3 years')
  FROM personnes p
) sub
ORDER BY random()
LIMIT 1500;

-- ============================================================
-- TÉLÉPHONES (1 000)
-- ============================================================
SELECT sub.* FROM (
  SELECT
    p.id,
    '+33' || (floor(random()*9+1)::int)::text ||
    lpad(floor(random()*99999999)::text, 8, '0'),
    (ARRAY['mobile','mobile','mobile','fixe','prepaye','professionnel']::type_telephone[])[floor(random()*6+1)::int],
    random() > 0.1,
    NOW() - (random() * interval '5 years')
  FROM personnes p
  UNION ALL
  SELECT
    p.id,
    '+33' || (floor(random()*9+1)::int)::text ||
    lpad(floor(random()*99999999)::text, 8, '0'),
    'prepaye'::type_telephone,
    random() > 0.3,
    NOW() - (random() * interval '3 years')
  FROM personnes p
) sub
ORDER BY random()
LIMIT 1000;

-- ============================================================
-- AFFAIRES (600)
-- ============================================================

-- ============================================================
-- AFFAIRE_PERSONNES (1 500 liens affaire ↔ personne)
-- ============================================================
SELECT DISTINCT ON (a.id, p.id)
  a.id,
  p.id,
  (ARRAY['mis_en_cause','victime','temoin','suspect','temoin_protege']::role_affaire[])[floor(random()*5+1)::int],
  a.date_faits + (random() * 10)::int,
  NOW() - (random() * interval '3 years')
FROM affaires a
CROSS JOIN LATERAL (
  SELECT id FROM personnes ORDER BY random() LIMIT 3
) p
LIMIT 1500;

-- ============================================================
-- AFFAIRE_INFRACTIONS (800 liens affaire ↔ infraction)
-- ============================================================
SELECT DISTINCT ON (a.id, inf.id) a.id, inf.id
FROM affaires a
CROSS JOIN LATERAL (
  SELECT id FROM infractions ORDER BY random() LIMIT 2
) inf
LIMIT 800;

-- ============================================================
-- SIGNALEMENTS (300)
-- ============================================================
SELECT
  p.id,
  (ARRAY['fiche_s','fiche_recherche','oqtf','mandat_arret','mandat_amener','avis_recherche','interdiction_territoire']::type_signalement[])[floor(random()*7+1)::int],
  (ARRAY[
    'Radicalisation islamiste — surveillance préventive',
    'Menace terroriste potentielle — fiché SNRT',
    'Trafic de stupéfiants avéré — réseau international',
    'Violences conjugales réitérées — suivi judiciaire',
    'Séjour irrégulier sur le territoire national',
    'Manquement à contrôle judiciaire',
    'Fuite après condamnation correctionnelle',
    'Suspicion appartenance organisation criminelle'
  ])[floor(random()*8+1)::int],
  CURRENT_DATE - (random() * 1825)::int,
  CASE WHEN random() > 0.3 THEN CURRENT_DATE + (random() * 730)::int ELSE NULL END,
  floor(random()*10+1)::int,
  (ARRAY[1,2,2,3,3,4])[floor(random()*6+1)::int],
  random() > 0.15,
  floor(random()*5+1)::int,
  NOW() - (random() * interval '4 years')
FROM personnes p
ORDER BY random()
LIMIT 300;

-- ============================================================
-- BIOMÉTRIE (500 — données chiffrées simulées)
-- ============================================================
SELECT
  p.id,
  (ARRAY['empreinte_digitale','photo_identite','adn','empreinte_palmaire','iris']::type_biometrie[])[floor(random()*5+1)::int],
  pgp_sym_encrypt(
    'BIOMETRIC_DATA_' || p.numero_taj || '_' || extract(epoch from now())::text,
    'blackvault_key_2026'
  ),
  encode(digest(p.numero_taj || '_biometric', 'sha256'), 'hex'),
  (ARRAY[2,3,3,4])[floor(random()*4+1)::int],
  CURRENT_DATE - (random() * 1825)::int,
  (ARRAY['Commissariat Central Paris','IRCGN Pontoise','Laboratoire de Lyon',
         'Brigade Criminelle Marseille','INPS Nantes'])[floor(random()*5+1)::int],
  NOW() - (random() * interval '4 years')
FROM personnes p
ORDER BY random()
LIMIT 500;

-- ============================================================
-- DÉCISIONS DE JUSTICE (400)
-- ============================================================
SELECT
  a.id,
  (ARRAY['condamnation','relaxe','acquittement','classement_sans_suite','non_lieu','sursis','sursis_probatoire','amende']::type_decision[])[floor(random()*8+1)::int],
  a.date_ouverture + (random() * 365)::int,
  (ARRAY[
    'Tribunal Correctionnel de Paris','Cour d''Assises de Paris',
    'Tribunal Correctionnel de Marseille','Cour d''Appel de Lyon',
    'Tribunal Correctionnel de Lille','Cour d''Appel de Versailles'
  ])[floor(random()*6+1)::int],
  (ARRAY[
    '2 ans d''emprisonnement ferme','5 ans de réclusion criminelle',
    '18 mois avec sursis probatoire','Amende de 5 000 euros',
    '10 ans de réclusion criminelle','Non-lieu — charges insuffisantes'
  ])[floor(random()*6+1)::int],
  'Décision rendue suite à instruction judiciaire',
  NOW() - (random() * interval '4 years')
FROM affaires a
WHERE a.statut IN ('cloturee','renvoi_correctionnel','renvoi_assises')
ORDER BY random()
LIMIT 400;

