-- ============================================================
-- VÉHICULES (200)
-- ============================================================

-- AFFAIRE_VEHICULES (250)
SELECT DISTINCT ON (a.id, v.id) a.id, v.id,
  (ARRAY['implique','saisi','recherche','vole','abandonne']::role_vehicule[])[floor(random()*5+1)::int],
  NOW() - (random() * interval '3 years')
FROM affaires a
CROSS JOIN LATERAL (SELECT id FROM vehicules ORDER BY random() LIMIT 1) v
LIMIT 250;

-- ============================================================
-- CONSULTATIONS (2 000 — traçabilité des accès)
-- ============================================================
SELECT
  a.id,
  (ARRAY['personnes','affaires','signalements','biometrie','decisions_justice','scelles'])[floor(random()*6+1)::int],
  gen_random_uuid(),
  NOW() - (random() * interval '2 years'),
  ('10.0.' || floor(random()*255)::int || '.' || floor(random()*255)::int)::inet,
  (ARRAY['Enquête en cours','Contrôle de routine','Vérification d''identité',
         'Réquisition judiciaire','Audit de conformité'])[floor(random()*5+1)::int],
  (ARRAY['select','select','select','insert','update']::type_requete[])[floor(random()*5+1)::int]
FROM agents a
CROSS JOIN generate_series(1, 40)
ORDER BY random()
LIMIT 2000;

-- ============================================================
-- AUDIT LOG (500 — alertes et événements)
-- ============================================================
SELECT
  NOW() - (random() * interval '2 years'),
  (SELECT id FROM agents ORDER BY random() LIMIT 1),
  (ARRAY['LOGIN','LOGOUT','SELECT','INSERT','UPDATE','DELETE','EXPORT','TENTATIVE_ACCES_REFUSE'])[floor(random()*8+1)::int],
  (ARRAY['personnes','affaires','signalements','biometrie','audit_log'])[floor(random()*5+1)::int],
  jsonb_build_object('ip', '10.0.' || floor(random()*255)::int || '.' || floor(random()*255)::int,
                     'user_agent', 'psql/16.0'),
  ('10.0.' || floor(random()*255)::int || '.' || floor(random()*255)::int)::inet,
  random() < 0.15,
  CASE WHEN random() < 0.15 THEN
    (ARRAY['NRU_VIOLATION','NWD_VIOLATION','HONEYTOKEN_ACCESS','BRUTE_FORCE'])[floor(random()*4+1)::int]
  ELSE NULL END,
  floor(random()*6)::int
FROM generate_series(1, 500);

COMMIT;

-- ============================================================
-- VÉRIFICATION : nombre de lignes par table
-- ============================================================
SELECT 'agents'            AS table_name, COUNT(*) FROM agents
UNION ALL SELECT 'personnes',              COUNT(*) FROM personnes
UNION ALL SELECT 'aliases',                COUNT(*) FROM aliases
UNION ALL SELECT 'adresses',               COUNT(*) FROM adresses
UNION ALL SELECT 'telephones',             COUNT(*) FROM telephones
UNION ALL SELECT 'affaires',               COUNT(*) FROM affaires
UNION ALL SELECT 'affaire_personnes',      COUNT(*) FROM affaire_personnes
UNION ALL SELECT 'affaire_infractions',    COUNT(*) FROM affaire_infractions
UNION ALL SELECT 'signalements',           COUNT(*) FROM signalements
UNION ALL SELECT 'biometrie',              COUNT(*) FROM biometrie
UNION ALL SELECT 'decisions_justice',      COUNT(*) FROM decisions_justice
UNION ALL SELECT 'scelles',                COUNT(*) FROM scelles
UNION ALL SELECT 'vehicules',              COUNT(*) FROM vehicules
UNION ALL SELECT 'affaire_vehicules',      COUNT(*) FROM affaire_vehicules
UNION ALL SELECT 'consultations',          COUNT(*) FROM consultations
UNION ALL SELECT 'audit_log',              COUNT(*) FROM audit_log
ORDER BY table_name;